use std::env;
use std::thread;

fn user_id_from_json(input_json: &str) -> String {
    let Some(key_start) = input_json.find("\"userId\"") else {
        return "ada".to_string();
    };
    let Some(after_key) = input_json[key_start..].find(':') else {
        return "ada".to_string();
    };
    let value_start = key_start + after_key + 1;
    let rest = input_json[value_start..].trim_start();
    let Some(stripped) = rest.strip_prefix('"') else {
        return "ada".to_string();
    };
    let Some(end) = stripped.find('"') else {
        return "ada".to_string();
    };
    stripped[..end].to_string()
}

fn load_user(user_id: String) -> String {
    format!("{user_id}:user")
}

fn load_profile(user_id: String) -> String {
    format!("{user_id}:profile")
}

fn merge(user: String, profile: String) -> String {
    format!("{user}|{profile}")
}

fn app(user_id: String) -> String {
    let user_id_for_profile = user_id.clone();
    let user = thread::spawn(move || load_user(user_id));
    let profile = thread::spawn(move || load_profile(user_id_for_profile));
    merge(user.join().unwrap(), profile.join().unwrap())
}

fn main() {
    let input_json = env::args()
        .nth(1)
        .unwrap_or_else(|| "{\"userId\":\"ada\"}".to_string());
    println!("{}", app(user_id_from_json(&input_json)));
}
